{"content": "     1|import { readFileSync, existsSync } from 'fs'
     2|import path from 'path'
     3|
     4|interface PageConfig {
     5|  id: string
     6|  title: string
     7|  sections: string[]
     8|  [key: string]: any
     9|}
    10|
    11|interface ContentData {
    12|  [key: string]: any
    13|}
    14|
    15|function getContent(): ContentData {
    16|  const contentPath = path.join(process.cwd(), 'content', 'es.json')
    17|  if (existsSync(contentPath)) {
    18|    return JSON.parse(readFileSync(contentPath, 'utf-8'))
    19|  }
    20|  return {}
    21|}
    22|
    23|function getPages() {
    24|  const pagesDir = path.join(process.cwd(), 'pages')
    25|  try {
    26|    const pageFiles = require('fs').readdirSync(pagesDir)
    27|    const pages: Record<string, PageConfig> = {}
    28|    for (const file of pageFiles) {
    29|      if (file.endsWith('.json')) {
    30|        const data = JSON.parse(readFileSync(path.join(pagesDir, file), 'utf-8'))
    31|        pages[file.replace('.json', '')] = data
    32|      }
    33|    }
    34|    return pages
    35|  } catch {
    36|    return { home: { id: 'home', title: 'Home', sections: ['hero'] } }
    37|  }
    38|}
    39|
    40|export default function HomePage() {
    41|  const content = getContent()
    42|  const pages = getPages()
    43|  const homePage = pages['home'] || pages['index'] || { id: 'home', title: 'Home' }
    44|  
    45|  return (
    46|    <main className="min-h-screen">
    47|      <h1 className="text-4xl font-bold text-center py-12">
    48|        {homePage.title || content?.title || 'Welcome'}
    49|      </h1>
    50|      
    51|      {homePage.sections?.map((section: string) => {
    52|        const sectionContent = content?.[section]
    53|        if (!sectionContent) return null
    54|        
    55|        if (typeof sectionContent === 'string') {
    56|          return <p key={section} className="text-lg px-4 py-2">{sectionContent}</p>
    57|        }
    58|        
    59|        if (Array.isArray(sectionContent)) {
    60|          return (
    61|            <section key={section} className="px-4 py-8 max-w-6xl mx-auto">
    62|              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
    63|                {sectionContent.map((item: any, i: number) => (
    64|                  <div key={i} className="p-6 rounded-lg" style={{backgroundColor: 'var(--color-surface, #f8f9fa)'}}>
    65|                    {item.title && <h3 className="text-xl font-semibold mb-2">{item.title}</h3>}
    66|                    {item.description && <p>{item.description}</p>}
    67|                    {item.price && <p className="text-lg font-bold mt-2">{item.price}</p>}
    68|                  </div>
    69|                ))}
    70|              </div>
    71|            </section>
    72|          )
    73|        }
    74|        
    75|        return null
    76|      })}
    77|    </main>
    78|  )
    79|}
